const PlasmicDescendants = {
  root: [
    "root",
    "softBackground2",
    "border2",
    "interactionEffect2",
    "pageBanner",
    "h1",
    "section",
    "foreground",
    "copy",
    "softBackground3",
    "border3",
    "interactionEffect3",
    "art",
    "h2",
    "softBackground",
    "border",
    "interactionEffect",
    "footerTop",
    "container",
    "footerBottom",
    "container2"
  ],
  softBackground2: ["softBackground2"],
  border2: ["border2"],
  interactionEffect2: ["interactionEffect2"],
  pageBanner: ["pageBanner", "h1"],
  h1: ["h1"],
  section: ["section", "foreground"],
  foreground: ["foreground"],
  copy: ["copy", "softBackground3", "border3", "interactionEffect3"],
  softBackground3: ["softBackground3"],
  border3: ["border3"],
  interactionEffect3: ["interactionEffect3"],
  art: ["art"],
  h2: ["h2"],
  softBackground: ["softBackground"],
  border: ["border"],
  interactionEffect: ["interactionEffect"],
  footerTop: ["footerTop", "container"],
  container: ["container"],
  footerBottom: ["footerBottom", "container2"],
  container2: ["container2"]
} as const;
type NodeNameType = keyof typeof PlasmicDescendants;
type DescendantsType<T extends NodeNameType> =
  (typeof PlasmicDescendants)[T][number];
type NodeDefaultElementType = {
  root: "div";
  softBackground2: "div";
  border2: "div";
  interactionEffect2: "div";
  pageBanner: "div";
  h1: "h1";
  section: "section";
  foreground: "div";
  copy: "div";
  softBackground3: "div";
  border3: "div";
  interactionEffect3: "div";
  art: "div";
  h2: "h2";
  softBackground: "div";
  border: "div";
  interactionEffect: "div";
  footerTop: "div";
  container: "div";
  footerBottom: "div";
  container2: "div";
};

type ReservedPropsType = "variants" | "args" | "overrides";
type NodeOverridesType<T extends NodeNameType> = Pick<
  PlasmicFeatures__OverridesType,
  DescendantsType<T>
>;
type NodeComponentProps<T extends NodeNameType> =
  // Explicitly specify variants, args, and overrides as objects
  {
    variants?: PlasmicFeatures__VariantsArgs;
    args?: PlasmicFeatures__ArgsType;
    overrides?: NodeOverridesType<T>;
  } &
    // Specify variants directly as props
    Omit<PlasmicFeatures__VariantsArgs, ReservedPropsType> &
    // Specify args directly as props
    Omit<PlasmicFeatures__ArgsType, ReservedPropsType> &
    // Specify overrides for each element directly as props
    Omit<
      NodeOverridesType<T>,
      ReservedPropsType | VariantPropType | ArgPropType
    > &
    // Specify props for the root element
    Omit<
      Partial<React.ComponentProps<NodeDefaultElementType[T]>>,
      ReservedPropsType | VariantPropType | ArgPropType | DescendantsType<T>
    >;

function makeNodeComponent<NodeName extends NodeNameType>(nodeName: NodeName) {
  type PropsType = NodeComponentProps<NodeName> & { key?: React.Key };
  const func = function <T extends PropsType>(
    props: T & StrictProps<T, PropsType>
  ) {
    const { variants, args, overrides } = React.useMemo(
      () =>
        deriveRenderOpts(props, {
          name: nodeName,
          descendantNames: PlasmicDescendants[nodeName],
          internalArgPropNames: PlasmicFeatures__ArgProps,
          internalVariantPropNames: PlasmicFeatures__VariantProps
        }),
      [props, nodeName]
    );
    return PlasmicFeatures__RenderFunc({
      variants,
      args,
      overrides,
      forNode: nodeName
    });
  };
  if (nodeName === "root") {
    func.displayName = "PlasmicFeatures";
  } else {
    func.displayName = `PlasmicFeatures.${nodeName}`;
  }
  return func;
}

export const PlasmicFeatures = Object.assign(
  // Top-level PlasmicFeatures renders the root element
  makeNodeComponent("root"),
  {
    // Helper components rendering sub-elements
    softBackground2: makeNodeComponent("softBackground2"),
    border2: makeNodeComponent("border2"),
    interactionEffect2: makeNodeComponent("interactionEffect2"),
    pageBanner: makeNodeComponent("pageBanner"),
    h1: makeNodeComponent("h1"),
    section: makeNodeComponent("section"),
    foreground: makeNodeComponent("foreground"),
    copy: makeNodeComponent("copy"),
    softBackground3: makeNodeComponent("softBackground3"),
    border3: makeNodeComponent("border3"),
    interactionEffect3: makeNodeComponent("interactionEffect3"),
    art: makeNodeComponent("art"),
    h2: makeNodeComponent("h2"),
    softBackground: makeNodeComponent("softBackground"),
    border: makeNodeComponent("border"),
    interactionEffect: makeNodeComponent("interactionEffect"),
    footerTop: makeNodeComponent("footerTop"),
    container: makeNodeComponent("container"),
    footerBottom: makeNodeComponent("footerBottom"),
    container2: makeNodeComponent("container2"),

    // Metadata about props expected for PlasmicFeatures
    internalVariantProps: PlasmicFeatures__VariantProps,
    internalArgProps: PlasmicFeatures__ArgProps,

    // Page metadata
    pageMetadata: {
      title: "",
      description: "",
      ogImageSrc: "",
      canonical: ""
    }
  }
);

export default PlasmicFeatures;
